using System;using System.Collections.Generic;class A{static int R,C,px,py,wb,ex,tx,ty;static string[]G;static int[]dx={1,-1,0,0},dy={0,0,1,-1};static string[]dn={"RIGHT","LEFT","DOWN","UP"};static Dictionary<int,int>Bfs(char goal,string avoid){var q=new Queue<(int,int)>();var cf=new Dictionary<int,int>();var vis=new HashSet<int>();q.Enqueue((px,py));vis.Add(py*C+px);while(q.Count>0){var(x,y)=q.Dequeue();for(int i=0;i<4;i++){int nx=x+dx[i],ny=y+dy[i],k=ny*C+nx;if(nx>=0&&nx<C&&ny>=0&&ny<R&&!vis.Contains(k)&&avoid.IndexOf(G[ny][nx])<0){vis.Add(k);cf[k]=y*C+x;q.Enqueue((nx,ny));if(G[ny][nx]==goal){tx=nx;ty=ny;return cf;}}}}tx=ty=-1;return cf;}static void Main(){var p=Console.ReadLine().Split(' ');R=int.Parse(p[0]);C=int.Parse(p[1]);for(;;){p=Console.ReadLine().Split(' ');py=int.Parse(p[0]);px=int.Parse(p[1]);G=new string[R];for(int y=0;y<R;y++){G[y]=Console.ReadLine();for(int x=0;x<C;x++)if(G[y][x]=='C'&&x==px&&y==py)wb=1;}Dictionary<int,int>cf;if(ex==0){cf=Bfs('?',"#C");if(tx<0)ex=1;}if(ex>0)cf=wb>0?Bfs('T',"#"):Bfs('C',"#");else cf=Bfs('?',"#C");int cx=tx,cy=ty;while(cf.ContainsKey(cy*C+cx)){int v=cf[cy*C+cx],nx2=v%C,ny2=v/C;if(nx2==px&&ny2==py)break;cx=nx2;cy=ny2;}for(int i=0;i<4;i++)if(px+dx[i]==cx&&py+dy[i]==cy){Console.WriteLine(dn[i]);break;}}}}